import{_ as s,c as a,o as e,d as m}from"./plugin-vue_export-helper.23b45acd.js";const f='{"title":"\u0413\u043B\u0430\u0432\u0430 1","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 1","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-12-01T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/1.md","lastUpdated":1625429283581}',i={},d=m('<div class="stanza"><a href="#s1.1-5" id="s1.1-5" class="num">1.1-5</a><p>(\u0412\u043E\u0438\u0441\u0442\u0438\u043D\u0443, \u0432\u0441\u0435\u0433\u0434\u0430) \u043F\u043E\u0431\u0435\u0436\u0434\u0430\u044E\u0442 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u043E\u0431\u0435\u0437\u043E\u0440\u0443\u0436\u0438\u0432\u0430\u044E\u0449\u0435\u0435 \u0432\u0440\u0430\u0433\u0430 \u043C\u0438\u043B\u043E\u0441\u0435\u0440\u0434\u0438\u0435, \u043B\u0443\u0447\u0438 \u043B\u0443\u043D\u044B \u0417\u043D\u0430\u043D\u0438\u044F, \u0438\u0437\u043E\u0448\u0435\u0434\u0448\u0435\u0433\u043E \u0438\u0437 \u0443\u0441\u0442 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0412\u043B\u0430\u0434\u044B\u043A\u0438, \u0421\u043F\u0430\u0441\u0438\u0442\u0435\u043B\u044F \u0442\u043E\u043D\u0443\u0449\u0438\u0445 \u0432 \u043C\u0438\u0440\u0441\u043A\u043E\u043C \u043E\u043A\u0435\u0430\u043D\u0435, \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0433\u043E \u0421\u043F\u0430\u0441\u0438\u0442\u0435\u043B\u044F. (\u041D\u0435\u043A\u043E\u0433\u0434\u0430) \u0432\u0435\u043B\u0438\u043A\u0438\u0435 \u0440\u0438\u0448\u0438 - \u0421\u0430\u043D\u0430\u0442\u043A\u0443\u043C\u0430\u0440\u0430, \u0421\u0430\u043D\u0430\u043A\u0430, \u0421\u0430\u043D\u0430\u0442\u0430\u043D\u0430, \u0421\u0430\u043D\u0430\u043D\u0434\u0430\u043D\u0430, \u041D\u0430\u0440\u0430\u0434\u0430, \u0410\u0433\u0430\u0441\u0442\u044C\u044F, \u0412\u0430\u0441\u0438\u0448\u0442\u0445\u0430, \u0438 \u0434\u0440\u0443\u0433\u0438\u0435, \u0436\u0435\u043B\u0430\u044F \u043F\u043E\u0437\u043D\u0430\u0442\u044C \u0412\u044B\u0441\u0448\u0443\u044E \u0418\u0441\u0442\u0438\u043D\u0443, \u043E\u0431\u0440\u0430\u0442\u0438\u043B\u0438\u0441\u044C \u043A \u0428\u0438\u0432\u0435 \u0438 \u0428\u0430\u043A\u0442\u0438. \u041F\u043E\u0447\u0442\u0438\u0432 (\u0438\u0445), \u043A\u0430\u043A \u043F\u043E\u0434\u043E\u0431\u0430\u0435\u0442, \u043E\u043D\u0438 \u0440\u0430\u0434\u043E\u0441\u0442\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u043B\u0438: \xAB\u041E \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u043C\u044B \u043F\u0440\u0438\u0431\u044B\u043B\u0438, \u0436\u0435\u043B\u0430\u044F (\u043E\u0431\u0440\u0435\u0441\u0442\u0438) \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u0439\u043E\u0433\u0435. \u041F\u043E\u0432\u0435\u0434\u0430\u0439 (\u043D\u0430\u043C) \u043E \u0439\u043E\u0433\u0435, \u0431\u0435\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043D\u0435\u0442 \u0432\u044B\u0445\u043E\u0434\u0430 \u0438\u0437 \u0442\u044C\u043C\u044B, \u0438 \u043A \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u0442\u0440\u0435\u043C\u044F\u0442\u0441\u044F \u043C\u0443\u0434\u0440\u0435\u0446\u044B, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 (\u0441 \u0422\u043E\u0431\u043E\u0439).</p></div><div class="stanza"><a href="#s1.6-7" id="s1.6-7" class="num">1.6-7</a><p>\u0421 \u0440\u0430\u0434\u043E\u0441\u0442\u043D\u044B\u043C \u0441\u0435\u0440\u0434\u0446\u0435\u043C \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u044B\u0439 \u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0430 \u043E\u0442\u0432\u0435\u0442\u0438\u043B: \xAB\u0421\u043B\u0443\u0448\u0430\u0439\u0442\u0435, \u043F\u043E\u0432\u0435\u0434\u0430\u044E (\u0432\u0430\u043C) \xAB<em>\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0443</em>\xBB, \u0434\u0430\u044E\u0449\u0443\u044E \u043F\u043B\u043E\u0434 \u0432\u0441\u0435\u0445 \u0441\u0438\u0434\u0434\u0445\u0438, \u0438\u0437\u043E\u0448\u0435\u0434\u0448\u0443\u044E \u0438\u0437 \u0443\u0441\u0442 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0412\u043B\u0430\u0434\u044B\u043A\u0438, \u0434\u0430\u044E\u0449\u0443\u044E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435, \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0443\u044E \u0412\u043B\u0430\u0434\u044B\u043A\u043E\u0439 \u0423\u043C\u044B \u0438 \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u043D\u044B\u043C\u0438 (\u0431\u043E\u0433\u0430\u043C\u0438)\xBB.</p></div><div class="stanza"><a href="#s1.8-12" id="s1.8-12" class="num">1.8-12</a><p>\u041F\u043E\u043A\u043B\u043E\u043D\u0438\u0432\u0448\u0438\u0441\u044C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u043C\u0443 \u0432\u043D\u0443\u0442\u0440\u0438 \u0421\u0435\u0431\u044F (\u0428\u0438\u0432\u0435), \u0411\u043E\u0433\u0438\u043D\u044F \u0423\u043C\u0430 \u0441\u043A\u0430\u0437\u0430\u043B\u0430 \u0442\u0430\u043A: \xAB<em>\u0421\u0438\u0434\u0445\u0430\u0439\u043E\u0433\u0435\u0448\u0432\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430</em>, \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043D\u0430\u044F \u0440\u0430\u043D\u0435\u0435 \u0422\u043E\u0431\u043E\u0439 \u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437 \u0434\u0435\u0432\u044F\u043D\u043E\u0441\u0442\u043E \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 \u0448\u043B\u043E\u043A, \u0431\u044B\u043B\u0430 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0430 \u0432 \u0442\u0440\u0438 \u0440\u0430\u0437\u0430. \u0412 <em>\u043C\u0430\u043B\u0438\u043D\u0438\u0432\u0438\u0434\u0436\u0430\u0439\u0435</em> \u0442\u0430\u043D\u0442\u0440\u0435, \u043D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u044E\u0449\u0435\u0439 \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u044C \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 (\u0448\u043B\u043E\u043A) \u0422\u043E\u0431\u043E\u0439 \u043F\u043E\u0434\u0440\u043E\u0431\u043E \u043E\u043F\u0438\u0441\u0430\u043D \u043F\u0443\u0442\u044C \u0439\u043E\u0433\u0438, \u043E \u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0430! \u0412\u043D\u043E\u0432\u044C \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u0430\u044F \u0434\u043E \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u0438 \u0442\u044B\u0441\u044F\u0447 (\u0448\u043B\u043E\u043A), \u043E\u043D\u0430 \u0431\u044B\u043B\u0430 \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u0430 \u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u043C\u0443\u0434\u0440\u044B\u043C\u0438. \u0421\u043E\u043A\u0440\u0430\u0442\u0438\u0432 \u0435\u0435 \u0441\u043D\u043E\u0432\u0430, \u043F\u043E \u0442\u0432\u043E\u0435\u0439 \u043C\u0438\u043B\u043E\u0441\u0442\u0438 \u043F\u0443\u0441\u0442\u044C \u043E\u043D\u0430 \u0434\u0430\u044E\u0449\u0430\u044F \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u0430 \u0434\u043B\u044F \u043F\u043E\u043B\u044C\u0437\u044B \u0441\u043A\u0443\u0434\u043E\u0443\u043C\u043D\u044B\u0445. \u041D\u0430 \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 \u0442\u0430\u043A \u0411\u043E\u0433\u0438\u043D\u0435\u0439, \u0412\u043B\u0430\u0434\u044B\u043A\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0443\u043B\u044B\u0431\u0430\u044F\u0441\u044C \u043E\u0442\u0432\u0435\u0442\u0438\u043B:</p></div><div class="stanza"><a href="#s1.13" id="s1.13" class="num">1.13</a><p>\u0421\u043B\u0443\u0448\u0430\u0439, \u0414\u0435\u0432\u0438, \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0422\u0435\u0431\u0435 \u0443\u0447\u0435\u043D\u0438\u0435 <em>\u0421\u0438\u0434\u0434\u0445\u0438\u0439\u043E\u0433\u0435\u0448\u0432\u0430\u0440\u0438</em> - <em>\u041C\u0430\u043B\u0438\u043D\u0438\u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430</em> (\u0442\u0430\u043D\u0442\u0440\u0443), \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0440\u0430\u043D\u0435\u0435 \u043D\u0438\u043A\u043E\u043C\u0443 \u043D\u0435 \u0441\u043E\u043E\u0431\u0449\u0430\u043B\u0430\u0441\u044C.</p></div><div class="stanza"><a href="#s1.14" id="s1.14" class="num">1.14</a><p>(\u041E\u043D\u0430 \u0431\u044B\u043B\u0430) \u0440\u0430\u043D\u0435\u0435 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0430 \u041C\u043D\u043E\u0439 \u043E\u0442 \u0410\u0433\u0445\u043E\u0440\u044B, \u0412\u044B\u0441\u0448\u0435\u0433\u043E \xAB\u042F\xBB. \u0412 \u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043C\u044B\u0441\u043B\u0435 (\u0432\u0441\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C) - \u0435\u0441\u0442\u044C \u0442\u043E, \u0447\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u043D\u044F\u0442\u044C, \u0442\u043E, \u0447\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0431\u0440\u043E\u0441\u0438\u0442\u044C \u0438 \u0442\u043E, \u0447\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0437\u043D\u0430\u0442\u044C.</p></div><div class="stanza"><a href="#s1.15-16" id="s1.15-16" class="num">1.15-16</a><p>\u0428\u0438\u0432\u0430, \u0428\u0430\u043A\u0442\u0438, <em>\u0412\u0438\u0434\u0439\u0435\u0448\u0430</em>, <em>\u043C\u0430\u043D\u0442\u0440\u0430</em>, <em>\u041C\u0430\u043D\u0442\u0440\u0435\u0448\u0430</em>, \u0438 <em>\u0430\u043D\u0443</em> (\u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u043E\u0435 \xAB\u042F\xBB) - \u044D\u0442\u0430 \u0448\u0435\u0441\u0442\u0435\u0440\u043A\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0442\u0435\u043C, \u0447\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u043D\u044F\u0442\u044C \u0434\u043B\u044F \u0441\u0442\u0440\u0435\u043C\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u0446\u0435\u043B\u0438. \u041C\u0430\u043B\u0430- \u043C\u0430\u0439\u0430 \u0438 \u043A\u0430\u0440\u043C\u0430 \u0438 \u0432\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F, \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u0439\u0435, \u0432\u0441\u0435 \u044D\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0431\u0440\u043E\u0441\u0438\u0442\u044C. \u042D\u0442\u043E \u0436\u0435, \u043A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F, - \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0437\u043D\u0430\u0442\u044C.</p></div><div class="stanza"><a href="#s1.17" id="s1.17" class="num">1.17</a><p>\u041F\u043E\u0437\u043D\u0430\u0432 \u044D\u0442\u043E \u0438 \u043E\u0442\u0431\u0440\u043E\u0441\u0438\u0432, (\u0430\u0434\u0435\u043F\u0442) \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0432\u0441\u0435\u0445 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432. (\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C), \u0418\u0448\u0430, (\u0412\u043B\u0430\u0434\u044B\u043A\u0430), \u0421\u043F\u043E\u043A\u043E\u0439\u043D\u044B\u0439, \u0412\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0438\u0439. \u0412\u0441\u0435\u0442\u0432\u043E\u0440\u044F\u0449\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C.</p></div><div class="stanza"><a href="#s1.18" id="s1.18" class="num">1.18</a><p>\u041E\u043D \u0422\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u043D\u044B\u0439 \u0438 \u0418\u043C\u043C\u0430\u043D\u0435\u043D\u0442\u043D\u044B\u0439 (<em>\u0441\u0430\u043A\u0430\u043B\u0430</em> \u0438 <em>\u043D\u0438\u0448\u043A\u0430\u043B\u0430</em>) \u0442\u0430\u043A\u043E\u0432\u0430 \u0436\u0435 \u0415\u0433\u043E \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u0430\u044F \u0428\u0430\u043A\u0442\u0438. \u0421\u0432\u043E\u0435\u044E \u0412\u043E\u043B\u0435\u0439 (<em>\u0418\u0447\u0447\u0445\u0430 \u0428\u0430\u043A\u0442\u0438</em>) \u041E\u043D \u0436\u0435\u043B\u0430\u0435\u0442 \u0441\u043E\u0442\u0432\u043E\u0440\u0438\u0442\u044C \u0432 \u041D\u0430\u0447\u0430\u043B\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E.</p></div><div class="stanza"><a href="#s1.19-22" id="s1.19-22" class="num">1.19-22</a><p>\u0412 (\u0415\u0433\u043E) \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438 \u044F\u0432\u0438\u043B\u043E\u0441\u044C \u0432\u043E\u0441\u0435\u043C\u044C \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439: \u0410\u0433\u0445\u043E\u0440\u0430, \u041F\u0430\u0440\u0430\u043C\u0430\u0433\u0445\u043E\u0440\u0430, \u0413\u0445\u043E\u0440\u0430\u0440\u0443\u043F\u0430, \u0422\u0430\u0434\u0430\u043D\u0430\u043D\u0430, \u0411\u0445\u0438\u043C\u0430, \u0411\u0445\u0438\u0448\u0430\u043D\u0430, \u0412\u0430\u043C\u0430\u043D\u0430 \u0438 \u041F\u0438\u0432\u0430\u043D\u0430. \u042D\u0442\u0438 (\u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438) \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u044E\u0442 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435, \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 \u0438 \u043C\u0438\u043B\u043E\u0441\u0442\u044C. \u0421\u043E\u0435\u0434\u0438\u043D\u044F\u044F\u0441\u044C \u0432 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u043C\u0430\u043D\u0442\u0440\u044B \u0438 \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438 \u043E\u043D\u0438 \u043F\u043E\u0440\u043E\u0434\u0438\u043B\u0438 \u0441\u0435\u043C\u044C\u0434\u0435\u0441\u044F\u0442 \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 \u043C\u0430\u043D\u0442\u0440 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043C\u0430\u043D\u0434\u0430\u043B\u0430\u043C\u0438. \u0412\u0441\u0435 \u044D\u0442\u0438 \u0432\u0435\u043B\u0438\u043A\u0438\u0435 \u0434\u0443\u0445\u043E\u043C _\u041C\u0430\u043D\u0442\u0440\u044B _\u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0442 \u0432\u0441\u0435\u043C\u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438. \xAB\u042F\xBB(\u0410\u0442\u043C\u0430\u043D) \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432, \u0432 \u043D\u0435\u043C (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442) \u0435\u0434\u0438\u043D\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s1.23" id="s1.23" class="num">1.23</a><p>\u0415\u0434\u0438\u043D\u043E\u0435 (\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435) \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F \u0441 (\u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435\u043C) <em>\u043C\u0430\u043B\u043E\u0439</em>, \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F \u0441 <em>\u043A\u0430\u0440\u043C\u043E\u0439</em> (\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0435\u0441\u0442\u044C) \u0435\u0434\u0438\u043D\u043E\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435. \u041A <em>\u043C\u0430\u043B\u0435</em> \u0438 \u043D\u0435-\u0437\u043D\u0430\u043D\u0438\u044E, \u043F\u0440\u0438\u0447\u0438\u043D\u0435, \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0435\u0439 <em>\u0441\u0430\u043C\u0441\u0430\u0440\u0443</em>, \u0441\u0442\u0440\u0435\u043C\u044F\u0442\u0441\u044F (\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430).</p></div><div class="stanza"><a href="#s1.24" id="s1.24" class="num">1.24</a><p><em>\u041A\u0430\u0440\u043C\u0430</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>\u0414\u0445\u0430\u0440\u043C\u044B</em> \u0438 <em>\u0430-\u0434\u0445\u0430\u0440\u043C\u044B</em>, \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u043C\u044B\u0435 \u043A\u0430\u043A \u0441\u0447\u0430\u0441\u0442\u044C\u0435 \u0438 \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435. \u041F\u043E\u0434 \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C \u0412\u043E\u043B\u0438 \u0418\u0448\u0432\u0430\u0440\u044B \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0439.</p></div><div class="stanza"><a href="#s1.25" id="s1.25" class="num">1.25</a><p>\u0414\u043B\u044F \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0436\u0435\u043B\u0430\u043D\u0438\u044F \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F, \u043A\u043E\u0440\u0435\u043D\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u0432 \u0441\u0435\u0440\u0434\u0446\u0435, \u0412\u043B\u0430\u0434\u044B\u043A\u0430 \u043C\u0430\u043D\u0442\u0440 \u043F\u043E\u0440\u043E\u0434\u0438\u043B \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u0443\u044E \u0441\u0438\u043B\u0430\u043C\u0438 \u043C\u0430\u0439\u0438.</p></div><div class="stanza"><a href="#s1.26" id="s1.26" class="num">1.26</a><p>\u041E\u043D\u0430 - \u0415\u0434\u0438\u043D\u044B\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u0441\u043A\u0438\u0439 \u043E\u043A\u0435\u0430\u043D \u0432 \u0444\u043E\u0440\u043C\u0435 <em>\u0412\u0439\u0430\u043F\u0438\u043D\u0438</em>. (\u041E\u043D\u0430) \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0439 \u043D\u0430\u0447\u0430\u043B\u0430 \u0438 \u043A\u043E\u043D\u0446\u0430, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0439 \u0433\u0438\u0431\u0435\u043B\u0438, \u0428\u0438\u0432\u043E\u0439 \u0438 \u0418\u0448\u0430\u043D\u0438 (\u0428\u0430\u043A\u0442\u0438).</p></div><div class="stanza"><a href="#s1.27" id="s1.27" class="num">1.27</a><p>\u041E\u043D\u0430 \u043F\u043E\u0440\u043E\u0434\u0438\u043B\u0430 <em>\u043A\u0430\u043B\u0410\u0442\u0430\u0442\u0442\u0432\u0443</em>, \u043E\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0441 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u0435\u043B \u041F\u0443\u0440\u0443\u0448\u0430. (\u0415\u0433\u043E) \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043A \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044E \u0441\u043E\u0442\u0432\u043E\u0440\u0438\u043B\u0430 \u0437\u0430\u0442\u0435\u043C _\u0432\u0438\u0434\u0439\u0443 _\u0438 <em>\u0440\u0410\u0433\u0443</em>.</p></div><div class="stanza"><a href="#s1.28-29" id="s1.28-29" class="num">1.28-29</a><p>\u0415\u0433\u043E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432\u0438\u0434\u0439\u0430 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442 \u043D\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u0443 \u0438 \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435. \u0415\u0433\u043E \u043D\u0438\u0437\u0448\u0438\u0435 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u044F\u0435\u0442_ \u0440\u0410\u0433\u0430_ (\u0443\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435). <em>\u041D\u0438\u0439\u0430\u0442\u0438</em> (\u0442\u0430\u0442\u0442\u0432\u0430) \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u0435\u0433\u043E \u0441 \u043B\u0438\u0447\u043D\u043E\u0439 \u043A\u0430\u0440\u043C\u043E\u0439, \u0432\u0440\u0435\u043C\u044F (<em>\u043A\u0410\u043B\u0430 \u0442\u0430\u0442\u0442\u0432\u0430</em>) \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u0438\u043C, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0441\u044F \u0432\u043E ( \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0438 \u0441 \u043E\u0442\u0440\u0435\u0437\u043A\u0430\u043C\u0438 \u0432\u0440\u0435\u043C\u0435\u043D\u0438), \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>\u0442\u0443\u0422\u0438</em>.</p></div><div class="stanza"><a href="#s1.30-32" id="s1.30-32" class="num">1.30-32</a><p>\u0417\u0430\u0442\u0435\u043C, \u0438\u0437 <em>\u043A\u0430\u043B\u0410\u0442\u0430\u0442\u0442\u0432\u044B</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>\u0430\u0432\u0439\u0430\u043A\u0442\u0430</em> (\u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0435), _\u0433\u0443\u043D\u044B _\u0438 \u0432\u043E\u0441\u0435\u043C\u044C \u043A\u0430\u0447\u0435\u0441\u0442\u0432, \u0438\u043C \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0435 \u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0449\u0430\u044F <em>\u0430\u0445\u0430\u043C\u043A\u0430\u0440\u0430</em>. \u041E\u043D\u0430 - \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432. \u0417\u0430\u0442\u0435\u043C, \u0438\u0437 \u043E\u0433\u043D\u044F \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0443\u043C \u0438 \u0441\u0438\u043B\u0430 \u0437\u0440\u0435\u043D\u0438\u044F. \u041E\u0442 (\u0438\u0445) \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043D\u0430 \u0442\u0440\u0435\u0442\u044C\u0435\u043C (\u044D\u0442\u0430\u043F\u0435) \u0443\u0445\u043E, \u043A\u043E\u0436\u0430, \u0433\u043B\u0430\u0437, \u044F\u0437\u044B\u043A - \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430, \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443; - \u0440\u0435\u0447\u044C, \u0440\u0443\u043A\u0438, \u043D\u043E\u0433\u0438, \u0430\u043D\u0443\u0441 \u0438 \u0433\u0435\u043D\u0438\u0442\u0430\u043B\u0438\u0438.</p></div><div class="stanza"><a href="#s1.33" id="s1.33" class="num">1.33</a><p>\u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>\u041A\u0430\u043B\u0410</em> (\u0442\u0430\u0442\u0442\u0432\u044B) \u0438 \u0434\u043E \u0437\u0435\u043C\u043B\u0438 \u0435\u0441\u0442\u044C \u0441\u0444\u0435\u0440\u0430 <em>\u0441\u0430\u043C\u0441\u0430\u0440\u044B</em>. \u041F\u043E \u0412\u043E\u043B\u0435 (\u0428\u0438\u0432\u044B) \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0432\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0428\u0438\u0432\u044B.</p></div><div class="stanza"><a href="#s1.34" id="s1.34" class="num">1.34</a><p>\u0420\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u043D\u0430 <em>\u043A\u0430\u043B\u0410</em> \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0447\u0435\u0440\u0435\u0437 <em>\u0431\u0445\u0443\u0432\u0430\u043D\u0443</em>, \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043E \u0432 <em>\u0442\u0430\u043C\u0430\u0441\u0435</em>, \u0434\u043B\u044F \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u0445\u0441\u044F, \u0440\u0430\u0434\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s1.35-40" id="s1.35-40" class="num">1.35-40</a><p><em>\u041F\u0443\u0440\u0443\u0448\u0438</em> (\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u044B\u0435 \u0434\u0443\u0448\u0438), \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 (\u0438\u0445) \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C \u044D\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, (\u0438 \u0442\u0430\u0442\u0442\u0432\u044B) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>\u043A\u0430\u043B\u0410</em> (<em>\u0442\u0430\u0442\u0442\u0432\u044B</em>) \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0437\u0435\u043C\u043B\u0435\u0439 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043A\u0430\u043A _\u0441\u0430\u043A\u0430\u043B\u0410 _(\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u044C). \u0412 \u044D\u0442\u0438\u0445 \u0442\u0440\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 (<em>\u043F\u0443\u0440\u0443\u0448\u0438</em>, \u0436\u0435\u043B\u0430\u043D\u0438\u044F, <em>\u0442\u0430\u0442\u0442\u0432\u044B</em> ?), \u0441\u043B\u0435\u0434\u0443\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u043C\u0438\u043B\u043E\u0441\u0442\u0438 (\u043E\u043D\u0438) \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u044E\u0442 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0448\u0430\u0433\u043E\u0432 (\u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F - <em>\u043A\u0440\u0430\u043C\u0430</em>) \u043E\u0431\u043E\u0438\u0445 - \u0428\u0438\u0432\u044B \u0438 \u0428\u0430\u043A\u0442\u0438. \u0422\u0430\u043A \u043F\u043E\u0432\u0441\u044E\u0434\u0443 \u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0434 \u0432\u043B\u0438\u044F\u043D\u0438\u0435\u043C \u0420\u0443\u0434\u0440 \u043F\u0440\u044F\u043C\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0428\u0438\u0432\u0430, \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u044B\u0439 \u0441 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>\u0410\u043D\u0433\u0443\u0448\u0442\u0430 \u043C\u0430\u0442\u0440\u044B</em> \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0441\u0442\u0430 \u0432\u043E\u0441\u0435\u043C\u043D\u0430\u0434\u0446\u0430\u0442\u044C\u044E (<em>\u0431\u0445\u0443\u0432\u0430\u043D\u0430\u043C\u0438).</em> \u041E\u043D\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0435 \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0411\u0440\u0430\u0445\u043C\u044B, \u0440\u0438\u0448\u0438, \u0432\u0435\u043B\u0438\u043A\u0438\u0435 \u0446\u0430\u0440\u0438, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u041C\u0430\u043D\u0443, \u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0449\u0438\u0435 \u043E\u0434\u0438\u043D\u0430\u043A\u043E\u0432\u044B\u0439 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0432\u0441\u0435\u043C (\u0441\u0443\u0449\u0438\u043C) \u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0414\u0430\u043D\u043D\u044B\u043C, \u041E\u0431\u0440\u0435\u0442\u0430\u0435\u043C\u044B\u043C, \u0438 \u041F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u044B\u043C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u043E\u0442 \u0411\u0440\u0430\u0445\u043C\u044B \u0438 \u0434\u043E \u0442\u0440\u0430\u0432\u0438\u043D\u043A\u0438 \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u0435\u0434\u0448\u0438\u043C\u0438 \u043E\u0442 \u0428\u0438\u0432\u044B.</p></div><div class="stanza"><a href="#s1.41" id="s1.41" class="num">1.41</a><p>\u0422\u0440\u0438\u0434\u0446\u0430\u0442\u044C \u0441 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u043E\u0439 \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 <em>\u043C\u0430\u043D\u0442\u0440</em>, \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u044E\u0449\u0438\u0435 \u0441 \u0428\u0438\u0432\u043E\u0439, \u043E\u0442 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u0430\u044F _\u043F\u0430\u0434\u0430 _\u0441\u0447\u0438\u0442\u0430\u044E\u0442\u0441\u044F \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u044E\u0449\u0438\u043C\u0438 <em>\u0430\u043D\u0443</em> (\u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0435 \u0438\u043C\u043F\u0435\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \xAB\u042F\xBB).</p></div><div class="stanza"><a href="#s1.42" id="s1.42" class="num">1.42</a><p>\u0412\u043E \u0432\u0440\u0435\u043C\u044F \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0441 \u0415\u0433\u043E (\u0428\u0438\u0432\u044B), \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F \u0428\u0438\u0432\u0430 \u0438 \u0428\u0430\u043A\u0442\u0438, (\u043E\u0442 \u044D\u0442\u043E\u0433\u043E)\u043E\u0431\u0440\u0430\u0437\u0443\u0435\u0442\u0441\u044F \u043F\u043E\u043A\u043E\u0439, \u0434\u0430\u044E\u0449\u0438\u0439 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s1.43" id="s1.43" class="num">1.43</a><p>\u0422\u043E\u0442, \u043A\u0442\u043E \u043F\u043E \u043D\u0435\u0437\u043D\u0430\u043D\u0438\u044E \u0443\u043A\u043B\u043E\u043D\u044F\u0435\u0442\u0441\u044F \u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F, \u0442\u043E\u0442 \u043D\u0435 \u0432\u0435\u0440\u043D\u0435\u0442\u0441\u044F \u043D\u0438 \u043A \u043A\u0430\u043A\u043E\u043C\u0443 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0443.</p></div><div class="stanza"><a href="#s1.44" id="s1.44" class="num">1.44</a><p>\u041A\u0442\u043E \u0441\u0432\u044F\u0437\u0430\u043D \u0441 \u0420\u0443\u0434\u0440\u043E\u0439 \u0438 \u0428\u0430\u043A\u0442\u0438 , \u0442\u043E\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D (\u0441 \u043D\u0438\u043C\u0438) \u043F\u043E \u0412\u043E\u043B\u0435 \u0428\u0438\u0432\u044B. \u041A \u044D\u0442\u043E\u043C\u0443 \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442, \u0440\u0430\u0434\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u0421\u0430\u0434\u0433\u0443\u0440\u0443.</p></div><div class="stanza"><a href="#s1.45" id="s1.45" class="num">1.45</a><p>\u041F\u043E\u0447\u0438\u0442\u0430\u044F \u0435\u0433\u043E, \u0438 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0438\u0432, \u043E\u043D (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0428\u0430\u043D\u043A\u0430\u0440\u0438. \u0412 \u0442\u043E\u0442 \u0436\u0435 \u043C\u0438\u0433, \u0434\u0430\u0436\u0435 \u043D\u0430\u0445\u043E\u0434\u044F\u0441\u044C \u0432 \u0442\u0435\u043B\u0435, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0428\u0438\u0432\u043E\u0439.</p></div><div class="stanza"><a href="#s1.46" id="s1.46" class="num">1.46</a><p>\u041E\u0431\u0440\u0435\u0442\u044F \u0439\u043E\u0433\u0430 \u0434\u0438\u043A\u0448\u0443, \u0438 \u043F\u043E\u0437\u043D\u0430\u0432 \u0435\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0439\u043E\u0433\u0443. \u0422\u043E\u0433\u0434\u0430 (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E \u0432 \u0439\u043E\u0433\u0435, \u0430 \u043F\u043E\u0441\u043B\u0435, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0432\u0435\u0447\u043D\u043E\u0441\u0442\u0438.</p></div><div class="stanza"><a href="#s1.47" id="s1.47" class="num">1.47</a><p>\u042D\u0442\u0438\u043C \u043F\u0443\u0442\u0435\u043C \u0439\u043E\u0433\u0438 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0432\u044B\u0441\u0448\u0435\u0435 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435. \u0422\u043E\u0433\u0434\u0430 (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u043D\u0435 \u0441\u0442\u0430\u043D\u0435\u0442 \u0432\u043D\u043E\u0432\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C (\u0443\u0437\u0430\u043C\u0438 <em>\u043F\u0430\u0448\u0430</em>), \u043D\u043E \u043F\u0440\u0435\u0431\u0443\u0434\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u043C \u0447\u0438\u0441\u0442\u043E\u043C \u0410\u0442\u043C\u0430\u043D\u0435.</p></div><div class="stanza"><a href="#s1.48" id="s1.48" class="num">1.48</a><p>\u042D\u0442\u043E\u0442 \u0410\u0442\u043C\u0430\u043D (\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439) \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432, \u0438 \u043E\u043F\u044F\u0442\u044C \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044E \u043E\u0431 \u044D\u0442\u0438\u0445 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F\u0445 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C \u0410\u0442\u043C\u0430\u043D\u043E\u043C.</p></div><div class="stanza"><a href="#s1.49" id="s1.49" class="num">1.49</a><p>\u0422\u0440\u0438 (\u0432\u0438\u0434\u0430 \u0441\u0430\u0434\u0445\u0430\u043D\u044B) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>\u043D\u0438\u0442\u0439\u0430</em> \u0434\u043E\u043B\u0436\u043D\u044B \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0442\u044C \u0438 \u0433\u0443\u0440\u0443 \u0438 \u0441\u0430\u0434\u0445\u0430\u043A\u0430. \u041E\u0431\u0440\u044F\u0434 <em>\u043D\u0438\u0442\u0439\u0430</em> \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0434\u0432\u0430, \u0434\u043E\u043B\u0436\u043D\u044B \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0442\u044C\u0441\u044F, \u043F\u043E\u043A\u0430 \u0436\u0438\u0432 \u0441\u0430\u0434\u0445\u0430\u043A\u0430, \u0442\u0430\u043A\u043E\u0432\u0430 \u0412\u043E\u043B\u044F \u0428\u0438\u0432\u044B.</p></div><div class="stanza"><a href="#s1.50" id="s1.50" class="num">1.50</a><p>\u041E \u043A\u0430\u0436\u0434\u043E\u043C, \u0414\u0430\u043D\u043D\u043E\u043C, \u041E\u0431\u0440\u0435\u0442\u0430\u0435\u043C\u043E\u043C, \u0438 \u041F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u043C \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043E (\u0422\u0435\u0431\u0435). \u041F\u043E\u0437\u043D\u0430\u0432 \u0438\u0445 (\u0430\u0434\u0435\u043F\u0442) \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u0435\u043C \u0432\u0441\u0435\u0445 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432.</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430\xBB \u0442\u0430\u043D\u0442\u0440\u0435 \u043F\u0435\u0440\u0432\u0430\u044F \u0433\u043B\u0430\u0432\u0430.</p>',30),c=[d];function n(p,l,t,v,r,_){return e(),a("div",null,c)}var h=s(i,[["render",n]]);export{f as __pageData,h as default};
